/// subcommand below stays as-is — it handles `--symlink-dir`
/// overrides, interactive replacement prompts, and the `--list`
/// flag, none of which fit the simpler "create the default
/// workspace link" callsite.
pub fn install(project_dir: &Path) -> Result<SymLink, Box<dyn std::error::Error>> {
    let home = std::env::var("HOME")
        .map_err(|_| "HOME environment variable not set".to_string())?;
    let symlink_dir = PathBuf::from(home).join(".claude").join("projects");
    let sl = SymLink::new(project_dir, Path::new(".claude"), &symlink_dir)?;
    sl.create(false)?;
    info!(
        "Created symlink: {} -> {}",
        sl.symlink_path.display(),
        sl.abs_target.display()
    );
    Ok(sl)
