12	    Replace { current_target: PathBuf },
13	    /// The symlink already points to the correct target — nothing to do.
14	    AlreadyCorrect,
15	}
16	
17	/// A planned symlink operation.
18	#[derive(Debug)]
19	pub struct SymLink {
20	    /// Absolute path to the target directory (what the symlink points to).
21	    pub abs_target: PathBuf,
22	    /// Full path of the symlink to create/replace.
23	    pub symlink_path: PathBuf,
24	    /// What action is needed.
25	    pub action: SymlinkAction,
26	}
27	
28	/// Encode a path the way Claude Code does: replace `/` and `.` with `-`.
29	pub fn encode_path(path: &str) -> String {
30	    path.replace(['/', '.'], "-")
31	}
32	
33	/// Read what exists at a path without following symlinks.
34	///
35	/// Returns:
36	/// - `None` — nothing exists
37	/// - `Some(None)` — exists but is not a symlink
38	/// - `Some(Some(target))` — symlink pointing to target
39	fn probe(path: &Path) -> Option<Option<PathBuf>> {
40	    match path.symlink_metadata() {
41	        Err(_) => None,
42	        Ok(meta) => {
43	            if meta.is_symlink() {
44	                Some(Some(std::fs::read_link(path).unwrap_or_default())) // OK: TOCTOU race after symlink_metadata; empty PathBuf forces recreate
45	            } else {
46	                Some(None)
47	            }
48	        }
49	    }
50	}
51	
52	impl SymLink {
53	    /// Plan a symlink operation by probing the filesystem.
54	    ///
55	    /// # Arguments
56	    /// * `cwd` — current working directory (used to derive the symlink name)
57	    /// * `target` — the directory the symlink should point to (resolved to absolute)
58	    /// * `symlink_dir` — parent directory for the symlink (e.g. `~/.claude/projects`)
59	    pub fn new(cwd: &Path, target: &Path, symlink_dir: &Path) -> Result<Self, String> {
60	        let abs_target = if target.is_absolute() {
61	            target.to_path_buf()
62	        } else {
63	            cwd.join(target)
64	        };
65	
66	        let cwd_str = cwd
67	            .to_str()
68	            .ok_or_else(|| "current directory path is not valid UTF-8".to_string())?;
69	        let symlink_name = encode_path(cwd_str);
70	        let symlink_path = symlink_dir.join(symlink_name);
71	
72	        let action = match probe(&symlink_path) {
73	            None => SymlinkAction::Create,
74	            Some(None) => {
75	                return Err(format!(
76	                    "'{}' exists and is not a symlink",
77	                    symlink_path.display()
78	                ));
79	            }
80	            Some(Some(current_target)) => {
81	                if current_target == abs_target {
82	                    SymlinkAction::AlreadyCorrect
83	                } else {
84	                    SymlinkAction::Replace { current_target }
85	                }
86	            }
87	        };
88	
89	        Ok(SymLink {
90	            abs_target,
91	            symlink_path,
92	            action,
93	        })
94	    }
95	
96	    /// Plan a symlink operation from pre-probed metadata (for testing).
97	    #[cfg(test)]
98	    pub fn with_meta(
99	        cwd: &Path,
100	        target: &Path,
101	        symlink_dir: &Path,
102	        symlink_meta: Option<Option<PathBuf>>,
103	    ) -> Result<Self, String> {
104	        let abs_target = if target.is_absolute() {
105	            target.to_path_buf()
106	        } else {
107	            cwd.join(target)
108	        };
109	
110	        let cwd_str = cwd
111	            .to_str()
112	            .ok_or_else(|| "current directory path is not valid UTF-8".to_string())?;
113	        let symlink_name = encode_path(cwd_str);
114	        let symlink_path = symlink_dir.join(symlink_name);
115	
116	        let action = match symlink_meta {
117	            None => SymlinkAction::Create,
118	            Some(None) => {
119	                return Err(format!(
120	                    "'{}' exists and is not a symlink",
121	                    symlink_path.display()
122	                ));
123	            }
124	            Some(Some(current_target)) => {
125	                if current_target == abs_target {
126	                    SymlinkAction::AlreadyCorrect
127	                } else {
128	                    SymlinkAction::Replace { current_target }
129	                }
130	            }
131	        };
132	
133	        Ok(SymLink {
134	            abs_target,
135	            symlink_path,
136	            action,
137	        })
138	    }
139	
140	    /// Execute the symlink operation: create the target dir if needed, create/replace the symlink.
141	    pub fn create(&self, create_target: bool) -> Result<(), String> {
142	        debug!(
143	            "symlink {} -> {}",
144	            self.symlink_path.display(),
145	            self.abs_target.display()
146	        );
147	
148	        if create_target && !self.abs_target.exists() {
149	            std::fs::create_dir_all(&self.abs_target).map_err(|e| {
150	                format!("cannot create target '{}': {e}", self.abs_target.display())
151	            })?;
152	        }
153	
154	        if let Some(parent) = self.symlink_path.parent() {
155	            std::fs::create_dir_all(parent).map_err(|e| {
156	                format!(
157	                    "cannot create symlink directory '{}': {e}",
158	                    parent.display()
159	                )
160	            })?;
161	        }
162	
163	        match &self.action {
164	            SymlinkAction::Create => {}
165	            SymlinkAction::Replace { .. } => {
166	                std::fs::remove_file(&self.symlink_path).map_err(|e| {
167	                    format!(
168	                        "cannot remove existing symlink '{}': {e}",
169	                        self.symlink_path.display()
170	                    )
171	                })?;
172	            }
173	            SymlinkAction::AlreadyCorrect => return Ok(()),
174	        }
175	
176	        #[cfg(unix)]
177	        std::os::unix::fs::symlink(&self.abs_target, &self.symlink_path).map_err(|e| {
178	            format!(
179	                "cannot create symlink '{}' -> '{}': {e}",
180	                self.symlink_path.display(),
181	                self.abs_target.display()
182	            )
183	        })?;
184	
185	        #[cfg(not(unix))]
186	        return Err("symlink creation is only supported on Unix".to_string());
187	
188	        Ok(())
189	    }
190	}
