194	/// `vc-x1 symlink` subcommand.
195	fn default_symlink_dir() -> Result<PathBuf, Box<dyn std::error::Error>> {
196	    let home =
197	        std::env::var("HOME").map_err(|_| "HOME environment variable not set".to_string())?;
198	    Ok(PathBuf::from(home).join(".claude").join("projects"))
